mapper.insert:
INSERT INTO USER_FEED_CATEGORY (
    USER_ID,
    BBS_CTGR_CD
) VALUES (
    #{userId},
    #{bbsCtgrCd}
)
ON CONFLICT (USER_ID, BBS_CTGR_CD) DO NOTHING

mapper.select:
SELECT PST_ID
FROM USER_FEED_READ
WHERE USER_ID = #{userId}

mapper.insert:
INSERT INTO USER_FEED_READ (
    USER_ID,
    PST_ID
) VALUES (
    #{userId},
    #{pstId}
)
ON CONFLICT (USER_ID, PST_ID) DO UPDATE SET
    READ_DT = CURRENT_TIMESTAMP

INSERT INTO USER_SAVED_POST (
    USER_ID,
    PST_ID
) VALUES (
    #{userId},
    #{pstId}
)
ON CONFLICT (USER_ID, PST_ID) DO NOTHING

mapper.delete:
DELETE FROM USER_SAVED_POST
WHERE USER_ID = #{userId}
  AND PST_ID = #{pstId}

mapper.insert:
INSERT INTO USER_FAVORITE_USER (
    USER_ID,
    TARGET_USER_ID
) VALUES (
    #{userId},
    #{targetUserId}
)
ON CONFLICT (USER_ID, TARGET_USER_ID) DO NOTHING

mapper.delete:
DELETE FROM USER_FAVORITE_USER
WHERE USER_ID = #{userId}
  AND TARGET_USER_ID = #{targetUserId}

mapper.select:
SELECT COUNT(*)
FROM USER_FAVORITE_USER
WHERE USER_ID = #{userId}
  AND TARGET_USER_ID = #{targetUserId}

mapper.delete:
DELETE FROM USER_TODO
WHERE USER_ID = #{userId}
